[CmdletBinding(SupportsShouldProcess=$true)]
param([switch]$ClearCache,[switch]$ResetProfileSettings,[switch]$RepairWebView2,[switch]$RestartUpdateServices,[switch]$Force,[string]$OutputPath="$env:USERPROFILE\Desktop\EdgeRepair")
$ErrorActionPreference='Stop';New-Item -ItemType Directory -Path $OutputPath -Force|Out-Null;$Log=Join-Path $OutputPath ("repair-{0:yyyyMMdd-HHmmss}.log"-f(Get-Date));function L($m){"$(Get-Date -Format s) $m"|Tee-Object -FilePath $Log -Append};if(-not($ClearCache-or$ResetProfileSettings-or$RepairWebView2-or$RestartUpdateServices)){throw'Choose at least one repair action.'}
$edge=Get-Process msedge -ErrorAction SilentlyContinue;if($edge-and-not$Force){throw'Close Edge or use -Force.'};if($edge){$edge|Stop-Process -Force}
if($ClearCache){foreach($p in @("$env:LOCALAPPDATA\Microsoft\Edge\User Data\Default\Cache","$env:LOCALAPPDATA\Microsoft\Edge\User Data\Default\Code Cache","$env:LOCALAPPDATA\Microsoft\Edge\User Data\Default\GPUCache")){if(Test-Path $p){if($PSCmdlet.ShouldProcess($p,'Clear Edge cache')){Get-ChildItem $p -Force -ErrorAction SilentlyContinue|Remove-Item -Recurse -Force -ErrorAction SilentlyContinue}}};L'Edge cache cleared.'}
if($ResetProfileSettings){$prefs="$env:LOCALAPPDATA\Microsoft\Edge\User Data\Default\Preferences";if(Test-Path $prefs){Copy-Item $prefs (Join-Path $OutputPath 'Preferences.backup') -Force;if($PSCmdlet.ShouldProcess($prefs,'Reset Edge preference file')){Remove-Item $prefs -Force;L'Edge preferences reset.'}}}
if($RepairWebView2){$setup=Get-ChildItem "$env:ProgramFiles(x86)\Microsoft\EdgeWebView\Application" -Filter setup.exe -Recurse -ErrorAction SilentlyContinue|Select-Object -First 1 -Expand FullName;if(-not$setup){throw'WebView2 setup not found.'};if($PSCmdlet.ShouldProcess('WebView2 Runtime','Repair')){Start-Process $setup '--repair --msedgewebview --system-level' -Wait;L'WebView2 repair completed.'}}
if($RestartUpdateServices){foreach($s in'edgeupdate','edgeupdatem'){if(Get-Service $s -ErrorAction SilentlyContinue){if($PSCmdlet.ShouldProcess($s,'Restart service')){Restart-Service $s -Force -ErrorAction SilentlyContinue;L"Restarted $s"}}}}
L'Repair workflow finished.'